import{_ as e,o as l,c as a,a2 as i}from"./chunks/framework.BWSdbvGU.js";const s="/CS-Note/assets/640-1.BBzHZVJf.png",n="/CS-Note/assets/640-2.XkKcHWjP.webp",r="/CS-Note/assets/640-1688491669277-10.CWTcYsvC.png",d="/CS-Note/assets/image-20220126171936792.-y3FgdVu.png",o="/CS-Note/assets/image-20220126172239296.DsNmuefc.png",p="/CS-Note/assets/1629446588-fpMLVA-B%E6%A0%91.DWXCzcaL.png",h="/CS-Note/assets/%E6%9C%80%E5%B7%A6%E5%89%8D%E7%BC%80%E5%8C%B9%E9%85%8DB_%E6%A0%91.142UTKr0.png",g="/CS-Note/assets/20210909121053.Cq_sPrF4.png",c="/CS-Note/assets/20210909120959.CVG3NzFd.png",b="/CS-Note/assets/885859-20190729184808306-758660222.CmhEv7kF.png",y="/CS-Note/assets/885859-20190729184911699-676257427.C7-0_FR-.png",k="/CS-Note/assets/640-1682300016517-3.qmGh27Xz.png",u="/CS-Note/assets/640-1682414762577-11.B9y_fUPH.png",m="/CS-Note/assets/640-1682356712373-13.CFK3FkUT.png",A=JSON.parse('{"title":"SQL","description":"","frontmatter":{},"headers":[],"relativePath":"MySQL.md","filePath":"MySQL.md","lastUpdated":1780390825000}'),f={name:"MySQL.md"};function x(E,t,q,B,L,D){return l(),a("div",null,[...t[0]||(t[0]=[i('<p>MySQL</p><h1 id="sql" tabindex="-1">SQL <a class="header-anchor" href="#sql" aria-label="Permalink to &quot;SQL&quot;">​</a></h1><h2 id="类型" tabindex="-1">类型 <a class="header-anchor" href="#类型" aria-label="Permalink to &quot;类型&quot;">​</a></h2><p>DDL：数据定义语言，如CREATE、DROP、ALTER</p><p>DQL：数据查询语言（<strong>Query</strong>），如SELECT</p><p>DML：数据操作语言，如INSERT、UPDATE、DELETE</p><p>DCL：数据控制语言，如GRANT、REVOKE、COMMIT、ROLLBACK</p><h2 id="q-drop、delete-与-truncate-的区别" tabindex="-1">Q：DROP、DELETE 与 TRUNCATE 的区别？ <a class="header-anchor" href="#q-drop、delete-与-truncate-的区别" aria-label="Permalink to &quot;Q：DROP、DELETE 与 TRUNCATE 的区别？&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>DROP</th><th>DELETE</th><th>TRUNCATE</th></tr></thead><tbody><tr><td>类型</td><td>DDL</td><td>DML</td><td>DDL</td></tr><tr><td>回滚</td><td>不可</td><td>可</td><td>可</td></tr><tr><td>范围</td><td>全表数据+结构</td><td>全表或某些行数据</td><td>全表数据</td></tr><tr><td>速度</td><td>最快</td><td>慢</td><td>快</td></tr></tbody></table><h2 id="比较运算符" tabindex="-1">比较运算符 <a class="header-anchor" href="#比较运算符" aria-label="Permalink to &quot;比较运算符&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">符号</th><th style="text-align:left;">描述</th><th style="text-align:left;">备注</th></tr></thead><tbody><tr><td style="text-align:left;">!=</td><td style="text-align:left;">不等于</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">&lt;&gt;</td><td style="text-align:left;">不等于</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;">BETWEEN</td><td style="text-align:left;">在两值之间</td><td style="text-align:left;">相当于<code>&gt;=min &amp;&amp; &lt;=max</code></td></tr><tr><td style="text-align:left;">NOT BETWEEN</td><td style="text-align:left;">不在两值之间</td><td style="text-align:left;">相当于`&lt;min</td></tr><tr><td style="text-align:left;">&lt;=&gt;</td><td style="text-align:left;">严格比较两个值是否相等，包括NULL</td><td style="text-align:left;">当col1，col2两个可能存在NULL值的列需要进行相等比较时，可以使用 col1 &lt;=&gt; col2，可以包括null=null的情况</td></tr></tbody></table><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h2><h1 id="数据类型" tabindex="-1">数据类型 <a class="header-anchor" href="#数据类型" aria-label="Permalink to &quot;数据类型&quot;">​</a></h1><h2 id="数值类型" tabindex="-1">数值类型 <a class="header-anchor" href="#数值类型" aria-label="Permalink to &quot;数值类型&quot;">​</a></h2><p>MySQL 支持所有标准 SQL 数值数据类型。</p><p>这些类型包括严格数值数据类型(INTEGER、SMALLINT、DECIMAL 和 NUMERIC)，以及近似数值数据类型(FLOAT、REAL 和 DOUBLE PRECISION)。</p><p>关键字INT是INTEGER的同义词，关键字DEC是DECIMAL的同义词。</p><p>BIT数据类型保存位字段值，并且支持 MyISAM、MEMORY、InnoDB 和 BDB表。</p><p>作为 SQL 标准的扩展，MySQL 也支持整数类型 TINYINT、MEDIUMINT 和 BIGINT。</p><p>下面的表显示了需要的每个整数类型的存储和范围，加粗的为常用</p><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">大小</th><th style="text-align:left;">范围（有符号）</th><th style="text-align:left;">范围（无符号）</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>TINYINT</strong></td><td style="text-align:left;">1 Bytes</td><td style="text-align:left;">[-128，127]</td><td style="text-align:left;">[0，255]</td><td style="text-align:left;">小整数值</td></tr><tr><td style="text-align:left;">SMALLINT</td><td style="text-align:left;">2 Bytes</td><td style="text-align:left;">[-32 768，32 767]</td><td style="text-align:left;">[0，65 535]</td><td style="text-align:left;">大整数值</td></tr><tr><td style="text-align:left;">MEDIUMINT</td><td style="text-align:left;">3 Bytes</td><td style="text-align:left;">[-8 388 608，8 388 607]</td><td style="text-align:left;">[0，16 777 215]</td><td style="text-align:left;">大整数值</td></tr><tr><td style="text-align:left;">INT或INTEGER</td><td style="text-align:left;">4 Bytes</td><td style="text-align:left;">[-2 147 483 648，2 147 483 647]</td><td style="text-align:left;">[0，4 294 967 295]</td><td style="text-align:left;">大整数值</td></tr><tr><td style="text-align:left;"><strong>BIGINT</strong></td><td style="text-align:left;">8 Bytes</td><td style="text-align:left;">[-9,223,372,036,854,775,808，9 223 372 036 854 775 807]</td><td style="text-align:left;">[0，18 446 744 073 709 551 615]</td><td style="text-align:left;">极大整数值</td></tr><tr><td style="text-align:left;">FLOAT</td><td style="text-align:left;">4 Bytes</td><td style="text-align:left;">(-3.402 823 466 E+38，-1.175 494 351 E-38)，0，(1.175 494 351 E-38，3.402 823 466 351 E+38)</td><td style="text-align:left;">0，(1.175 494 351 E-38，3.402 823 466 E+38)</td><td style="text-align:left;">单精度 浮点数值</td></tr><tr><td style="text-align:left;">DOUBLE</td><td style="text-align:left;">8 Bytes</td><td style="text-align:left;">(-1.797 693 134 862 315 7 E+308，-2.225 073 858 507 201 4 E-308)，0，(2.225 073 858 507 201 4 E-308，1.797 693 134 862 315 7 E+308)</td><td style="text-align:left;">0，(2.225 073 858 507 201 4 E-308，1.797 693 134 862 315 7 E+308)</td><td style="text-align:left;">双精度 浮点数值</td></tr><tr><td style="text-align:left;">DECIMAL</td><td style="text-align:left;">对DECIMAL(M,D) ，如果M&gt;D，为M+2否则为D+2</td><td style="text-align:left;">依赖于M和D的值</td><td style="text-align:left;">依赖于M和D的值</td><td style="text-align:left;">小数值</td></tr></tbody></table><h2 id="日期和时间类型" tabindex="-1">日期和时间类型 <a class="header-anchor" href="#日期和时间类型" aria-label="Permalink to &quot;日期和时间类型&quot;">​</a></h2><p>表示时间值的日期和时间类型为DATETIME、DATE、TIMESTAMP、TIME和YEAR。</p><p>每个时间类型有一个有效值范围和一个&quot;零&quot;值，当指定不合法的MySQL不能表示的值时使用&quot;零&quot;值。</p><p>TIMESTAMP类型有专有的自动更新特性</p><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">大小 ( bytes)</th><th style="text-align:left;">范围</th><th style="text-align:left;">格式</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">DATE</td><td style="text-align:left;">3</td><td style="text-align:left;">1000-01-01/9999-12-31</td><td style="text-align:left;">YYYY-MM-DD</td><td style="text-align:left;">日期值</td></tr><tr><td style="text-align:left;">TIME</td><td style="text-align:left;">3</td><td style="text-align:left;">&#39;-838:59:59&#39;/&#39;838:59:59&#39;</td><td style="text-align:left;">HH:MM:SS</td><td style="text-align:left;">时间值或持续时间</td></tr><tr><td style="text-align:left;">YEAR</td><td style="text-align:left;">1</td><td style="text-align:left;">1901/2155</td><td style="text-align:left;">YYYY</td><td style="text-align:left;">年份值</td></tr><tr><td style="text-align:left;">DATETIME</td><td style="text-align:left;">8</td><td style="text-align:left;">&#39;1000-01-01 00:00:00&#39; 到 &#39;9999-12-31 23:59:59&#39;</td><td style="text-align:left;">YYYY-MM-DD hh:mm:ss</td><td style="text-align:left;">混合日期和时间值</td></tr><tr><td style="text-align:left;">TIMESTAMP</td><td style="text-align:left;">4</td><td style="text-align:left;">&#39;1970-01-01 00:00:01&#39; UTC 到 &#39;2038-01-19 03:14:07&#39; UTC结束时间是第 <strong>2147483647</strong> 秒，北京时间 <strong>2038-1-19 11:14:07</strong>，格林尼治时间 2038年1月19日 凌晨 03:14:07</td><td style="text-align:left;">YYYY-MM-DD hh:mm:ss</td><td style="text-align:left;">混合日期和时间值，时间戳</td></tr></tbody></table><h2 id="字符串类型" tabindex="-1">字符串类型 <a class="header-anchor" href="#字符串类型" aria-label="Permalink to &quot;字符串类型&quot;">​</a></h2><p>字符串类型指CHAR、VARCHAR、BINARY、VARBINARY、BLOB、TEXT、ENUM和SET</p><p><strong>注意</strong>：</p><ul><li><p>DDL中，char(n) 和 varchar(n) 中括号中 n 代表<strong>字符的个数</strong>，并不代表字节个数，比如 CHAR(30) 就可以存储 30 个字符。</p><blockquote><p>字节数根据编码而定，utf8编码最大字符长度为3字节。5.5.3版本以后支持<strong>utf8mb4</strong>编码（推荐使用），最大长度4字节。</p><p>两者最大区别在于utf8仅支持<strong>BMP</strong>（Basic Multilingual Plane）字符，即码位在0到65535之间(或者U+0000和U+FFFF)的字符。而BMP中不包含<strong>补充字符</strong>，即码位在U+10000和U+10FFFF，例如生僻汉字，或者Emoji表情。</p></blockquote></li><li><p>CHAR 和 VARCHAR 类型类似，但它们保存和检索的方式不同。它们的最大长度和是否尾部空格被保留等方面也不同。在存储或检索过程中不进行大小写转换。</p></li><li><p>BINARY 和 VARBINARY 类似于 CHAR 和 VARCHAR，不同的是它们包含二进制字符串而不要非二进制字符串。也就是说，它们包含字节字符串而不是字符字符串。这说明它们没有字符集，并且排序和比较基于列值字节的数值值。</p></li><li><p>BLOB 是一个<strong>二进制</strong>大对象，可以容纳可变数量的数据。有 4 种 BLOB 类型：TINYBLOB、BLOB、MEDIUMBLOB 和 LONGBLOB。它们区别在于可容纳存储范围不同。</p></li><li><p>有 4 种 TEXT 类型：TINYTEXT、TEXT、MEDIUMTEXT 和 LONGTEXT。对应的这 4 种 BLOB 类型，可存储的最大长度不同，可根据实际情况选择。</p></li></ul><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">大小</th><th style="text-align:left;">用途</th></tr></thead><tbody><tr><td style="text-align:left;">CHAR</td><td style="text-align:left;">0-255 bytes</td><td style="text-align:left;">定长字符串</td></tr><tr><td style="text-align:left;"><strong>VARCHAR</strong></td><td style="text-align:left;">0-65535 bytes</td><td style="text-align:left;"><strong>变长</strong>字符串</td></tr><tr><td style="text-align:left;">TINYBLOB</td><td style="text-align:left;">0-255 bytes</td><td style="text-align:left;">不超过 255 个字符的二进制字符串</td></tr><tr><td style="text-align:left;">TINYTEXT</td><td style="text-align:left;">0-255 bytes</td><td style="text-align:left;">短文本字符串</td></tr><tr><td style="text-align:left;">BLOB</td><td style="text-align:left;">0-65 535 bytes</td><td style="text-align:left;">二进制形式的长文本数据</td></tr><tr><td style="text-align:left;">TEXT</td><td style="text-align:left;">0-65 535 bytes</td><td style="text-align:left;">长文本数据</td></tr><tr><td style="text-align:left;">MEDIUMBLOB</td><td style="text-align:left;">0-16 777 215 bytes</td><td style="text-align:left;">二进制形式的中等长度文本数据</td></tr><tr><td style="text-align:left;">MEDIUMTEXT</td><td style="text-align:left;">0-16 777 215 bytes</td><td style="text-align:left;">中等长度文本数据</td></tr><tr><td style="text-align:left;">LONGBLOB</td><td style="text-align:left;">0-4 294 967 295 bytes</td><td style="text-align:left;">二进制形式的极大文本数据</td></tr><tr><td style="text-align:left;">LONGTEXT</td><td style="text-align:left;">0-4 294 967 295 bytes</td><td style="text-align:left;">极大文本数据</td></tr></tbody></table><h2 id="q-char和varchar区别" tabindex="-1">Q：char和varchar区别？ <a class="header-anchor" href="#q-char和varchar区别" aria-label="Permalink to &quot;Q：char和varchar区别？&quot;">​</a></h2><p>主要区别在于存储方式</p><ul><li><p>char是定长，在DDL指定字段长度（也就是<strong>字符个数</strong>，0~255），实际存储时不能超过，不够的在末尾用空格填充。</p><ul><li><p>优点：定长，内存碎片少</p></li><li><p>缺点：空间利用率低。</p></li></ul></li><li><p>varchar是可变长度（<strong>字符个数</strong>，0~65535），只存储实际的字符串内容，且需要额外空间记录长度。</p><ul><li><p>优点：灵活、兼容性好。</p></li><li><p>缺点：需要1~2字节存长度；产生内存碎片；由于变长，update可能导致页分裂</p><blockquote><p>表中数据刚开始插入时，可变长度字段值根据实际长度存储。而行与行之间数据紧密连续存放在磁盘，值变长就放不下了，需要页分裂扩展空间。</p></blockquote></li></ul></li></ul><p>举例：字符串以CHAR(4) 和 VARCHAR(4)存储需要的空间</p><table tabindex="0"><thead><tr><th style="text-align:left;">字符串</th><th style="text-align:left;"><code>CHAR(4)</code></th><th style="text-align:left;">所需存储空间</th><th style="text-align:left;"><code>VARCHAR(4)</code></th><th style="text-align:left;">所需存储空间</th></tr></thead><tbody><tr><td style="text-align:left;"><code>&#39;&#39;</code></td><td style="text-align:left;"><code>&#39; &#39;</code></td><td style="text-align:left;">4字节</td><td style="text-align:left;"><code>&#39;&#39;</code></td><td style="text-align:left;">1字节</td></tr><tr><td style="text-align:left;"><code>&#39;ab&#39;</code></td><td style="text-align:left;"><code>&#39;ab &#39;</code></td><td style="text-align:left;">4字节</td><td style="text-align:left;"><code>&#39;ab&#39;</code></td><td style="text-align:left;">3字节</td></tr><tr><td style="text-align:left;"><code>&#39;abcd&#39;</code></td><td style="text-align:left;"><code>&#39;abcd&#39;</code></td><td style="text-align:left;">4字节</td><td style="text-align:left;"><code>&#39;abcd&#39;</code></td><td style="text-align:left;">5字节</td></tr><tr><td style="text-align:left;"><code>&#39;abcdefgh&#39;</code></td><td style="text-align:left;"><code>&#39;abcd&#39;</code></td><td style="text-align:left;">4字节</td><td style="text-align:left;"><code>&#39;abcd&#39;</code></td><td style="text-align:left;">5字节</td></tr></tbody></table><h2 id="q-为什么-varchar-建议不要超过255" tabindex="-1">Q：为什么 VarChar 建议不要超过255? <a class="header-anchor" href="#q-为什么-varchar-建议不要超过255" aria-label="Permalink to &quot;Q：为什么 VarChar 建议不要超过255?&quot;">​</a></h2><ul><li><p>当定义varchar长度小于等于255时，长度标识位只需要一个字节(utf-8编码，0xffffffff=255)</p></li><li><p>当大于255时，长度标识位需要两个字节，并且建立的**「索引也会失效」**</p></li></ul><h2 id="q-text和blob区别" tabindex="-1">Q：TEXT和BLOB区别？ <a class="header-anchor" href="#q-text和blob区别" aria-label="Permalink to &quot;Q：TEXT和BLOB区别？&quot;">​</a></h2><ol><li>BLOB 可以储存图片，TEXT只能存纯文本（两者都可以存文本）。</li><li>BLOB 大小写敏感，TEXT不敏感。</li></ol><h2 id="q-为什么建议属性定义为not-null" tabindex="-1">Q：为什么建议属性定义为not null？ <a class="header-anchor" href="#q-为什么建议属性定义为not-null" aria-label="Permalink to &quot;Q：为什么建议属性定义为not null？&quot;">​</a></h2><ul><li><code>NULL</code> 代表 <strong>未知、不存在</strong></li><li>任何值 <strong>和 NULL 做比较</strong>，结果不是 <code>true/false</code>，而是 <strong>NULL</strong></li></ul><p>例如：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> XXX表 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> net_no </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1076</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>只会查出net_no = 1、2、3等非1076的数据行，而不会查出net_no=null的行。</p><p>因为条件<code>null ！= 1076</code>的结果不是false，而是NULL，所以<code>net_no=null</code>这一条数据在where语句的判断结果不为真，查不到这条。</p><p>解决：</p><ol><li>net_no属性定义为<code>NOT NULL</code></li><li>where语句增加条件：<code>OR net_no IS NULL</code></li></ol><hr><h1 id="mysql架构" tabindex="-1">MySQL架构 <a class="header-anchor" href="#mysql架构" aria-label="Permalink to &quot;MySQL架构&quot;">​</a></h1><p><img src="'+s+'" alt="图片"></p><p>主要分三层：</p><ul><li>客户端：最上层的服务并不是MySQL所独有的，大多数基于网络的客户端/服务器的工具或者服务都有类似的架构。比如连接处理、授权认证、安全等等。</li><li>Server层：大多数MySQL的核心服务功能都在这一层，包括查询<strong>解析、分析、优化、缓存</strong>以及所有的内置函数（例如，日期、时间、数学和加密函数），所有跨存储引擎的功能都在这一层实现：存储过程、触发器、视图等。</li><li>存储引擎层：负责MySQL中数据的存储和提取。Server层通过API与存储引擎进行通信。这些接口屏蔽了不同存储引擎之间的差异，使得这些差异对上层的查询过程透明。</li></ul><h1 id="sql执行过程" tabindex="-1">SQL执行过程 <a class="header-anchor" href="#sql执行过程" aria-label="Permalink to &quot;SQL执行过程&quot;">​</a></h1><ol><li><p>通过连接器跟客户端**「建立连接」**</p></li><li><p><strong>「验证权限」</strong>，验证客户端是否有权限执行该sql（读、写、读写权限等）。有才继续。</p></li><li><p>先看**「查询缓存」**。有则直接返回结果，没有则继续。</p><blockquote><p>查询缓存：本质是一个<strong>哈希表</strong>，key为sql、表名、db名、系统环境信息等，value为查询结果。</p><p>缓存写入：在获得查询结果时</p><p>缓存删除：表发生修改时，整个表的缓存都删除</p></blockquote></li><li><p>通过分析器对sql**「语义分析」**，检查语法是否正确。正确才继续</p></li><li><p>通过优化器**「sql优化」<strong>（比如选择索引，join 表的连接顺序），生成</strong>查询计划**</p></li><li><p>通过执行器调用**「存储引擎」<strong>执行该查询计划，然后返回</strong>执行结果**</p><p><img src="'+n+'" alt="图片"></p></li></ol><h1 id="索引" tabindex="-1">索引 <a class="header-anchor" href="#索引" aria-label="Permalink to &quot;索引&quot;">​</a></h1><p>数据库索引是 DBMS 中一个 排序的数据结构，以 协助快速查询、更新 数据库表中数据，通俗地说相当于目录。索引的实现通常使用 B 树以及变种 B+ 树。</p><h2 id="索引分类" tabindex="-1">索引分类 <a class="header-anchor" href="#索引分类" aria-label="Permalink to &quot;索引分类&quot;">​</a></h2><p><img src="'+r+'" alt="图片"></p><p>从基本使用使用的角度来讲：</p><ul><li>主键索引: InnoDB主键是默认的索引，数据列不允许重复，不允许为NULL，一个表只能有一个主键。</li><li>唯一索引: 数据列不允许重复，允许为NULL值，一个表允许多个列创建唯一索引。</li><li>普通索引: 基本的索引类型，没有唯一性的限制，允许为NULL值。</li><li>组合索引：多列值组成一个索引，用于组合搜索，效率大于索引合并</li></ul><p>从数据结构上分类：有哈希表、B树、B+树</p><p>从物理存储角度分类：聚簇索引和非聚簇索引</p><h2 id="b树索引" tabindex="-1">B树索引 <a class="header-anchor" href="#b树索引" aria-label="Permalink to &quot;B树索引&quot;">​</a></h2><p>B 树索引，又称 <strong>平衡树索引</strong>。MySQL、Oracle 和 SQL Server 数据库默认的都是 B 树索引（实际是用 B+ 树实现，只是查看表索引时打印BTREE）</p><p><img src="https://cs-notes-1256109796.cos.ap-guangzhou.myqcloud.com/45016e98-6879-4709-8569-262b2d6d60b9.png" alt="img"></p><h3 id="m阶b树性质" tabindex="-1">m阶B树性质 <a class="header-anchor" href="#m阶b树性质" aria-label="Permalink to &quot;m阶B树性质&quot;">​</a></h3><ol><li>若节点关键字（键）个数为k，则子节点个数（即指针个数）为k+1</li><li>键和数据一起存放</li><li>非叶节点由键+指针构成 <ul><li>键两侧各有一个指针</li><li>键左边指针指向<strong>小于等于</strong>当前关键字的子节点，右边则<strong>大于等于</strong>（见上图）</li><li>键从小到大排列</li></ul></li><li>根节点： <ul><li>最少2个子节点，最多m个（m阶的含义）</li><li>最少1个键，最多m-1个</li></ul></li><li>非根节点： <ul><li>最少$\\lceil m/2 \\rceil$个子节点，最多m个</li><li>最少$\\lceil m/2 \\rceil$-1个键，最多m-1个</li></ul></li><li>叶节点： <ul><li>在同一层</li><li>只放元素，没有指针</li></ul></li></ol><h3 id="查找过程" tabindex="-1">查找过程 <a class="header-anchor" href="#查找过程" aria-label="Permalink to &quot;查找过程&quot;">​</a></h3><p>B树索引中，从根节点开始，二分查找节点，直到叶节点，除了<strong>根节点常驻内存</strong>，其他结点都需要从磁盘载入内存（即一次IO）</p><p>定位叶节点后，将整个节点载入内存，在节点中查找关键字</p><h3 id="更新操作" tabindex="-1">更新操作 <a class="header-anchor" href="#更新操作" aria-label="Permalink to &quot;更新操作&quot;">​</a></h3><p><strong>插入</strong></p><p><strong>删除</strong></p><ol><li><p>直接删除</p><p>被删除关键字所在节点键数满足 大于 $\\lceil m/2 \\rceil$-1，则直接删除</p></li><li><p>兄弟够借</p><p>被删除键所在节点键数刚好为$\\lceil m/2 \\rceil$-1，则删除后不满足b树性质，需要从兄弟节点借一个</p><p>如下图，3阶b树，删除24，则该节点键数为0，不满足最少1个的约束，需要从左兄弟借一个21（不绝对，从右兄弟借也可）</p><p><img src="'+d+'" alt="image-20220126171936792"></p><p>借来之后21比父节点23小，需要再交换调整：</p><p><img src="'+o+'" alt="image-20220126172239296"></p></li><li><p>兄弟不够借</p></li></ol><h3 id="最大高度" tabindex="-1">最大高度 <a class="header-anchor" href="#最大高度" aria-label="Permalink to &quot;最大高度&quot;">​</a></h3><p>即节点最少</p><p>根最少2个子节点，非叶最少$\\lceil m/2 \\rceil$个子节点</p><h3 id="最小高度-log-m-n" tabindex="-1">最小高度：log~m~n <a class="header-anchor" href="#最小高度-log-m-n" aria-label="Permalink to &quot;最小高度：log~m~n&quot;">​</a></h3><p>每层都满，则所有节点之和为</p><p>1+m+m^2^+m^3^....+m^h−1^ = (m^h−1^)/(m−1)</p><p>每个节点都放满，则每个节点键最多为m-1，所有关键字上限为</p><p>（m-1) * (m^h−1^)/(m−1) = (m^h−1^)</p><p>记关键字数量为n，则n &lt;= (m^h−1^)，得</p><p>h &gt;= log~m~n</p><p>最小高度为：$$log_mn$$</p><h2 id="b-树索引" tabindex="-1">B+树索引 <a class="header-anchor" href="#b-树索引" aria-label="Permalink to &quot;B+树索引&quot;">​</a></h2><p><strong>b树</strong>结构如下</p><p><img src="'+p+'" alt="B树.png"></p><p><strong>b+树</strong>结构：</p><p>![B_ Tree.png](images\\MySQL\\1629448733-VWjqZc-B_ Tree.png)</p><h3 id="对b树的改进之处" tabindex="-1">对b树的改进之处 <a class="header-anchor" href="#对b树的改进之处" aria-label="Permalink to &quot;对b树的改进之处&quot;">​</a></h3><p>b+树由b树改进而来，大部分性质相同，与b树的不同在于：</p><ul><li><p>所有的非叶结点只存储 <strong>关键字信息</strong> 和指针，不再存放数据；所有<strong>数据都放叶子</strong>（b树非叶也放数据）</p><blockquote><p>因此扇出更多，m更大。</p></blockquote></li><li><p>所有叶子节点之间都有一个<strong>双向</strong>链指针。</p><blockquote><p>因此范围查找更快</p></blockquote></li></ul><p>优点：</p><ul><li>只存放键，不存放值，因此一次读取，可以在同一内存页中获取更多的键，有利于更快地缩小查找范围</li><li>叶结点由一条链相连，因此当需要进行一次<strong>全数据遍历</strong> 的时候，B+ 树只需要使用 O(logN) 时间找到最小结点，然后通过链进行 O(N) 的顺序遍历即可；或者在<strong>范围查找</strong>时，B+ 树只需要找到该关键字然后沿着链表遍历即可。</li></ul><h3 id="q-使用主键索引-b树和b-树哪个快" tabindex="-1">Q：使用主键索引，B树和B+树哪个快？ <a class="header-anchor" href="#q-使用主键索引-b树和b-树哪个快" aria-label="Permalink to &quot;Q：使用主键索引，B树和B+树哪个快？&quot;">​</a></h3><p>显然由于B树叶子和非叶节点都保存数据，导致非叶节点中保存的指针数量（也称为<strong>扇出</strong>，fanout）比B+树少，则相同数据量需要增加树的高度，IO操作变多，因此：</p><ul><li>若对单次查询，因为B+树必须查到叶子节点，而B树可能在非叶节点就已查到，因此快慢不一定</li><li>对多次查询，由于B+树高度较低，因此平均查找长度（即总体IO次数）比B树少，即b+树更快。</li><li>若不是主键索引，则B+树不一定快，因为要回表</li></ul><h3 id="q-是否m越大越好" tabindex="-1">Q：是否m越大越好？ <a class="header-anchor" href="#q-是否m越大越好" aria-label="Permalink to &quot;Q：是否m越大越好？&quot;">​</a></h3><p>不管是内存中的数据，还是磁盘中的数据，操作系统都是按页（一页大小通常是 4KB，这个值可以通过 getconfig PAGE_SIZE 命令查看）来读取的，一次会读一页的数据。**如果要读取的数据量超过一页的大小，就会触发多次 IO 操作。**所以，我们在选择 m 大小的时候，要尽量让每个节点的大小等于一个页的大小。读取一个节点，只需要一次磁盘 IO 操作</p><h3 id="q-b-树查找io次数计算" tabindex="-1">Q：B+树查找IO次数计算？ <a class="header-anchor" href="#q-b-树查找io次数计算" aria-label="Permalink to &quot;Q：B+树查找IO次数计算？&quot;">​</a></h3><p>Innodb的数据组织的最小单位是page（页），默认页大小<strong>16KB</strong>。由上面分析，让节点大小与页大小相等。非叶节点存主键(8B)+指针(6B，InnoDB源码设置) = 14B，每个非叶可以有 16KB/14B = 1170 个子节点。</p><p>假设一行数据大小为1KB，则叶节点能存放16KB/1KB = 16行数据</p><p>则高度为2的B+树可存放1170*16 = 18720行数据</p><p>高度为3可存放1170 * 1170 * 16=21902400行</p><p>所以高度为3的B+树主键索引能存放两千万+条数据，又由于根节点<strong>常驻内存</strong>，因此走到叶节点只需要<strong>两次IO</strong></p><h3 id="q-单表最大容量" tabindex="-1">Q：单表最大容量？ <a class="header-anchor" href="#q-单表最大容量" aria-label="Permalink to &quot;Q：单表最大容量？&quot;">​</a></h3><p>理论上没有上限，b+树越高存的越多，但超过三层会导致性能下降，所以最多三层，即两千万条左右。</p><h2 id="哈希索引" tabindex="-1">哈希索引 <a class="header-anchor" href="#哈希索引" aria-label="Permalink to &quot;哈希索引&quot;">​</a></h2><p>innodb本身的索引结构是B+tree，hash索引是innodb提供的特性功能。该功能是自适应的（非手动开关），innodb监控索引表，如果监控到某个索引经常用，那么就认为是热数据，然后内部自己创建一个hash索引</p><h3 id="q-hash索引和b-树索引区别" tabindex="-1">Q：Hash索引和B+树索引区别？ <a class="header-anchor" href="#q-hash索引和b-树索引区别" aria-label="Permalink to &quot;Q：Hash索引和B+树索引区别？&quot;">​</a></h3><ol><li>hash无法 范围查询 和 模糊查询，只支持<strong>等值查询</strong>，优点是更快（缺点是不稳定，当hash碰撞频繁时性能差，而B+树查询效率稳定）</li><li>hash不支持索引排序、多列索引的最左前缀匹配（因为hash不可预测）</li><li>hash避免不了回表查询。而B+树在聚簇索引、覆盖索引等可只用索引得到数据，不需要回表</li></ol><h2 id="最左前缀匹配原则" tabindex="-1">最左前缀匹配原则 <a class="header-anchor" href="#最左前缀匹配原则" aria-label="Permalink to &quot;最左前缀匹配原则&quot;">​</a></h2><p>一个联合索引是有先后顺序的，例如(a,b,c)。从最左边的索引列开始，任何连续的索引都能匹配上，当条件未命中，如<strong>缺失</strong>（相当于查该列全部）或是<strong>范围查询</strong>（如&gt;、&lt;、BETWEEN、LIKE、IN）就会停止匹配。（注意是索引顺序的最左，与查询条件的顺序无关，因为优化器能调整条件的顺序）</p><p><strong>具体规则</strong>：</p><ol><li><p>如果建立<code>(a,b)</code>顺序的索引，若查询条件为b=xxx，是无法命中<code>(a,b)</code>索引的（因为a缺失）；</p><p>若查询条件是<code>a=1 and b=2</code>或者<code>b=2 and a=1</code>都可以命中<code>(a,b)</code>索引（最左指的是索引的顺序，与where条件顺序无关）；</p></li><li><p>若查询条件为a = 1 and b = 2 and <strong>c &gt; 3</strong> and d = 4，对于索引<code>(a,b,c,d)</code>，d=4是用不到该索引的，因为c字段是一个范围查询，它之后的字段会停止匹配。 但这个索引不是完全失效，该查询会<strong>用到索引的一部分</strong>，即<code>(a，b，c)</code></p><p>而索引<code>(a,b,d,c)</code>能被查询条件<code>a = 1 and b = 2 and c &gt; 3 and d = 4</code>命中，因为范围查询的c列在索引的最后，且条件a、b、c的顺序能任意调整</p></li><li><p>（MySQL 8.0改进）对查询条件a = 1 and b = 2 and <strong>c &gt;= 3</strong> and d = 4，索引<code>(a,b,c,d)</code>生效，即<code>&gt;、&lt;、&gt;=、&lt;=、BETWEEN、like等</code> <strong>范围查询不会影响最左匹配</strong></p><blockquote><p><code>&gt;=</code> 虽然是范围，但也包括=号，属于精确匹配的特例，因此会命中索引</p><p><code>BETWEEN</code> 相当于&gt;=和&lt;=的集合</p><p><code>like</code>同理，</p></blockquote></li></ol><p>一条sql可能命中多个索引（explain查看<code>possible_keys</code>），最终走哪个索引由优化器基于<strong>成本预估</strong>来决定。</p><blockquote><p>explain命令：加在sql之前，用于查看执行计划，见 <a href="##查看执行计划（explain）">查看执行计划（explain）</a></p></blockquote><p><strong>原理</strong></p><p>索引的底层是一颗B+树，那么联合索引也还是一颗B+树，只不过联合索引的健值数量不是一个，而是多个。构建一颗B+树只能根据一个值来构建，因此数据库依据联合索引最左字段来构建B+树。</p><p>例如联合索引(a,b)的B+树：</p><p><img src="'+h+'" alt=""></p><p><strong>先按a值排序，当a值相等时，才按b值排序</strong>。因此当a用范围查询时，b是无序的，无法使用索引，即索引某列是<strong>范围查询</strong>时，其右侧的列无法使用索引。</p><p><strong>注意</strong></p><p>只是MySQL有这个限制，Oracle任意顺序都可以</p><h2 id="添加索引原则" tabindex="-1">添加索引原则 <a class="header-anchor" href="#添加索引原则" aria-label="Permalink to &quot;添加索引原则&quot;">​</a></h2><ol><li><p>很少使用的列不加索引（应该建在<strong>查询频繁</strong>的列，但修改频繁的列不适合）</p></li><li><p>区分度低的列不加（如性别只有两种，区分度低，加索引意义不大）</p></li><li><p>特殊数据类型不加（text、image和 bit）</p></li><li><p>有外键的列必须加</p></li><li><p>索引的个数应该适量（索引需要占用空间；表更新时候也需要维护。</p></li></ol><h2 id="索引失效场景" tabindex="-1">索引失效场景 <a class="header-anchor" href="#索引失效场景" aria-label="Permalink to &quot;索引失效场景&quot;">​</a></h2><p>下列都<strong>可能</strong>导致索引失效，而转向全表扫描</p><ol><li><p>违反最左前缀法则（对非最右端的索引使用范围条件&gt;、&lt;、between、in、等）</p></li><li><p>在索引上做任何操作（计算、<strong>函数</strong>、自动/手动类型转换），不然会导致索引失效而转向全表扫描</p><p>例如：<strong>DATE_FORMAT</strong>函数将create_date字段按&#39;%Y-%m-%d&#39;格式化后，再看是否等于&#39;2023-02-01&#39;。</p><p>但这样会导致不走create_date字段的索引：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sum_group_status_trend_create </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> group_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100000000034019</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> and</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> DATE_FORMAT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(create_date,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;%Y-%m-%d&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;2023-02-01&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>使用不等于（<code>!=</code> 或者 <code>&lt;&gt;</code>）判断时</p></li><li><p>使用 <code>is null</code> / <code>is not null</code> 判断</p></li><li><p>使用<code>like</code></p></li><li><p>索引字段是字符串，但查询时不加引号</p></li><li><p>（不一定失效）使用or</p></li></ol><h2 id="聚簇索引-主键索引" tabindex="-1">聚簇索引（主键索引） <a class="header-anchor" href="#聚簇索引-主键索引" aria-label="Permalink to &quot;聚簇索引（主键索引）&quot;">​</a></h2><p>并不是一种索引类型，而是一种数据存储方式，将 <strong>数据存储</strong> 和 <strong>索引</strong> 放到一起，找到索引也就找到了数据。</p><p>MySQL 里只有 <strong>INNODB</strong> 表支持聚簇索引，INNODB 表数据本身就是聚簇索引，非叶子节点按照主键顺序存放，叶子节点存放主键以及对应的行记录。所以对 INNODB 表进行全表顺序扫描会非常快。</p><p>特点：</p><ol><li>检索效率高，磁盘IO少（索引和数据放一起）</li><li>表的物理存储依据聚簇索引的结构，所以一个数据表只能有<strong>一个</strong>聚簇索引，但可以拥有多个非聚簇索引；</li><li>一般而言，会在频繁使用、排序的字段上创建聚簇索引。</li></ol><ul><li>定义了主键，则主键就是聚簇索引。</li><li>没定义主键，则找第一个<strong>唯一的not NULL列</strong>就是聚簇索引</li><li>还找不到，则innoDB创建一个隐藏的row-id作为聚簇索引，大小为<strong>6B</strong>。</li></ul><p><strong>非聚簇索引</strong></p><p>除了聚簇索引以外的其他索引，也称<strong>二级索引</strong>。</p><p>也是 <strong>B 树</strong>结构，与聚簇索引不同在于，非聚簇索引的叶节点不存储真正的数据行，只存储<strong>主键</strong>。查询得到主键后还需要再次到聚簇索引树中查找完整数据行，称为<strong>回表</strong>。</p><h2 id="索引下推" tabindex="-1">索引下推 <a class="header-anchor" href="#索引下推" aria-label="Permalink to &quot;索引下推&quot;">​</a></h2><p>Index Condition Pushdown (ICP)，MySQL5.6 添加的功能，用于优化数据查询。默认开启，可使用系统参数<code>optimizer_switch</code>控制</p><p>查询条件包含索引列时，将这些条件传给存储引擎，由存储引擎判断是否需要回表。其实就是将service层生成执行计划（选择索引）的工作交给下面，因此叫**“下推”**。</p><p>目的是为了<strong>减少回表</strong>，见下面两种情况：</p><ul><li><p>不使用索引下推，引擎层查找到<code>name like &#39;张%&#39;</code>的数据，再由Server层去过滤<code>age=10</code>这个条件，这样一来，就回表了<strong>两次</strong>，浪费了联合索引的另外一个字段<code>age</code>。</p><p><img src="'+g+'" alt="未使用ICP"></p></li><li><p>使用了索引下推优化，把where的条件放到了引擎层执行，直接根据<code>name like &#39;张%&#39; and age=10</code>的条件进行过滤，减少了回表的次数。只回表一次。</p><p><img src="'+c+`" alt="使用ICP的示意图"></p></li></ul><h2 id="回表" tabindex="-1">回表 <a class="header-anchor" href="#回表" aria-label="Permalink to &quot;回表&quot;">​</a></h2><p>如果索引的列在 select 选择的列中（因为在 mysql 中索引是根据索引列的值进行排序的，所以索引节点中存在该列中的部分值）或者根据一次索引查询就能获得记录就不需要回表。（即<strong>覆盖索引</strong>）</p><p>如果 select 选择列中有大量的非索引列，索引就需要到全表中找到相应的列的信息，<strong>先定位主键值，再定位数据行</strong>，这就叫<strong>回表</strong>。</p><p><strong>例子</strong></p><p>表t设计如下：</p><p><code>t(id PK, name KEY, sex, flag);</code> // id是主键，因此是聚集索引；name是普通索引</p><p>表中有四条记录：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1, shenjian, m, A</span></span>
<span class="line"><span>3, zhangsan, m, A</span></span>
<span class="line"><span>5, lisi, m, A</span></span>
<span class="line"><span>9, wangwu, f, B</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>两棵B+树索引分别如下图：</p><p>（1）id为PK，聚集索引，叶子节点存储行记录；</p><p>（2）name为KEY，普通索引，叶子节点存储PK值，即id；</p><p><img src="`+b+'" alt="img"></p><p>执行如下语句时</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>select * from  t  where name = &#39;lisi&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如下图<strong>粉红色</strong>路径，需要扫描<strong>两遍</strong>索引树：</p><p>（1）先通过普通索引（右边的树）定位到主键值id=5；</p><p>（2）在通过聚集索引定位到行记录；</p><p><img src="'+y+`" alt="img"></p><p><strong>如何避免回表</strong></p><p>使用聚集索引（主键或第一个唯一索引），不使用普通索引</p><h2 id="覆盖索引" tabindex="-1">覆盖索引 <a class="header-anchor" href="#覆盖索引" aria-label="Permalink to &quot;覆盖索引&quot;">​</a></h2><p>索引列包含了select选择的所有字段，就不需要回表了，只扫描索引树就能获得结果，可加快查询。</p><p>例如，name字段是user表的其中一个索引：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ‘张三’;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>实践</strong></p><p>避免使用select *</p><h2 id="q-为什么二级索引不直接存数据地址-而是存主键" tabindex="-1">Q：为什么二级索引不直接存数据地址，而是存主键？ <a class="header-anchor" href="#q-为什么二级索引不直接存数据地址-而是存主键" aria-label="Permalink to &quot;Q：为什么二级索引不直接存数据地址，而是存主键？&quot;">​</a></h2><p>当这行数据地址变化时，二级索引树也要做更新。而主键一般是不变的，存主键可以避免这部分开销</p><p>地址变化的情况：插入、更新或删除，可能引起聚簇索引b+树的变动（如节点分裂），进而导致地址变化</p><h2 id="q-为什么推荐使用自增-id-作为主键" tabindex="-1">Q：为什么推荐使用自增 id 作为主键？ <a class="header-anchor" href="#q-为什么推荐使用自增-id-作为主键" aria-label="Permalink to &quot;Q：为什么推荐使用自增 id 作为主键？&quot;">​</a></h2><ol><li>普通索引的 B+ 树上存放的是主键索引的值，如果该值较大，会**「导致普通索引的存储空间较大」**</li><li>使用自增 id 做主键索引新插入数据只要放在该页的最尾端就可以，直接**「按照顺序插入」**，不用刻意维护</li><li>页分裂容易维护，当插入数据的当前页快满时，会发生页分裂的现象，如果主键索引不为自增 id，那么数据就可能从页的中间插入，页的数据会频繁的变动，<strong>「导致页分裂维护成本较高」</strong></li></ol><p>但是也有缺点：</p><ul><li>受单机DB性能的限制，并发大时，innodb在按主键进行插入的时候会造成明显的锁争用，主键的上界会成为争抢的热点，因为所有的插入都发生在这里，并发插入会导致间隙锁竞争。</li><li>Auto_Increment锁机制会造成自增锁的抢夺。解决：调优innodb_autoinc_lock_mode的配置。</li><li>自增id容易暴露业务规模。</li></ul><h2 id="q-索引越多越好吗" tabindex="-1">Q：索引越多越好吗？ <a class="header-anchor" href="#q-索引越多越好吗" aria-label="Permalink to &quot;Q：索引越多越好吗？&quot;">​</a></h2><p>并不是，每建一条索引，都会新建一棵B+树，会占用内存，每个节点16KB。并且索引树的规模也会随着数据规模而倍增（插入一条数据，则所有索引树也都要改变）</p><h2 id="q-区分度不高的字段建索引一定没用吗" tabindex="-1">Q：区分度不高的字段建索引一定没用吗？ <a class="header-anchor" href="#q-区分度不高的字段建索引一定没用吗" aria-label="Permalink to &quot;Q：区分度不高的字段建索引一定没用吗？&quot;">​</a></h2><p>不一定。如果数据分布较为极端的特殊情况：</p><p>例如一个字段性别（加了索引），男女比例95：5，如果用女作为性别查询条件，还是可以走索引，并且有较大性能提升。原因是可以过滤掉大部分数据。</p><h2 id="全文索引" tabindex="-1">全文索引 <a class="header-anchor" href="#全文索引" aria-label="Permalink to &quot;全文索引&quot;">​</a></h2><p>MySQL 5.6 前，只有MyISAM 支持。MySQL 5.6 及以后，MyISAM 和 InnoDB 存储引擎均支持。</p><p>只有字段的数据类型为 char、varchar、text 及其系列才可以建全文索引。</p><p>全文索引 比 <code>like + %</code> 快 N 倍，但是可能存在精度问题。</p><p>创建：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">create</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> table</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> fulltext_test</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">11</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NOT NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> AUTO_INCREMENT,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    content </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">text</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> NOT NULL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    tag </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">varchar</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">255</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    PRIMARY KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (id),</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    FULLTEXT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> content_tag_fulltext(content,tag)  </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 创建联合全文索引列</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) ENGINE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">MyISAM </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DEFAULT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CHARSET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">utf8;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>使用：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># 与模糊匹配的like语法不同，全文索引使用 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">match</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 和 against 关键字</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># match函数必须完全对应全文索引，联合全文索引的列、顺序须完全一致</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># against函数中输入查询文本</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">select</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> fulltext_test </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> match</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(content,tag) against(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;xxx xxx&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h1 id="存储引擎" tabindex="-1">存储引擎 <a class="header-anchor" href="#存储引擎" aria-label="Permalink to &quot;存储引擎&quot;">​</a></h1><p>常见的有三种</p><h2 id="innodb" tabindex="-1">InnoDB <a class="header-anchor" href="#innodb" aria-label="Permalink to &quot;InnoDB&quot;">​</a></h2><p>InnoDB实现了四个标准隔离级别，是MySQL 默认的事务型存储引擎，因此默认隔离级别也是可重复读。通过多版本并发控制（MVCC）+ Next-Key Locking 防止幻读。</p><h2 id="myisam" tabindex="-1">MyISAM <a class="header-anchor" href="#myisam" aria-label="Permalink to &quot;MyISAM&quot;">​</a></h2><p>设计简单，数据以紧密格式存储。对于只读数据，或者表比较小、可以容忍修复操作，则依然可以使用它。</p><h2 id="memory" tabindex="-1">MEMORY <a class="header-anchor" href="#memory" aria-label="Permalink to &quot;MEMORY&quot;">​</a></h2><p>所有的数据都在<strong>内存</strong>中，速度快，但安全性不高。</p><p>不能建立太大的表。所以只使用在相对较小的数据库表，或者查询的临时表。</p><h2 id="q-几种存储引擎比较" tabindex="-1">Q：几种存储引擎比较？ <a class="header-anchor" href="#q-几种存储引擎比较" aria-label="Permalink to &quot;Q：几种存储引擎比较？&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>InnoDB</th><th>MyISAM</th><th>MEMORY</th></tr></thead><tbody><tr><td>事务</td><td>支持</td><td>不支持</td><td>不</td></tr><tr><td>外键</td><td>支持</td><td>不</td><td>不</td></tr><tr><td>主键（唯一索引）</td><td>必须有</td><td>可以没有</td><td></td></tr><tr><td>聚簇索引</td><td>聚簇索引</td><td>非聚簇索引</td><td></td></tr><tr><td>全文索引</td><td>支持</td><td>支持</td><td></td></tr><tr><td>哈希索引</td><td>支持</td><td>不</td><td>支持</td></tr><tr><td>count</td><td>不保存表具体行数</td><td>用一个变量保存</td><td></td></tr><tr><td>日志</td><td>redo log</td><td>没有</td><td></td></tr><tr><td>锁</td><td>表锁和行锁</td><td>只有表锁</td><td></td></tr><tr><td>存储容量</td><td>64TB</td><td>256TB</td><td>RAM（内存）</td></tr><tr><td>存储文件</td><td>表定义frm、数据ibd</td><td>frm、数据myd、myi索引</td><td></td></tr><tr><td>缓存</td><td>有</td><td>无</td><td>不需要</td></tr></tbody></table><h2 id="innodb执行更新语句流程" tabindex="-1">InnoDB执行更新语句流程 <a class="header-anchor" href="#innodb执行更新语句流程" aria-label="Permalink to &quot;InnoDB执行更新语句流程&quot;">​</a></h2><p>用以下语句来举例，c 字段无索引，id 为主键索引</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>update T set c=c+1 where id=2;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol><li><p>执行器先找引擎取 id=2 这一行。id 是主键，引擎直接用树搜索找到这一行</p></li><li><ul><li>若这一行所在的数据页本来就<strong>在内存中</strong>，就<strong>直接返回</strong>给执行器</li><li>若不在内存，需要先从磁盘读入内存，然后再返回</li></ul></li><li><p>执行器拿到引擎给的行数据，把这个值加1（ c=c+1），得到新的一行数据，再调用引擎接口写入这行新数据</p></li><li><p>引擎将这行新数据更新到内存中，同时将这个更新操作**记录到 redo log **，此时 redo log 处于 <strong>「prepare」</strong> 状态。然后告知执行器执行完成了，随时可以提交事务</p></li><li><p>执行器<strong>生成这个操作的 binlog</strong>，并把 binlog <strong>「写入磁盘」</strong></p></li><li><p>执行器调用引擎的<strong>提交事务</strong>接口，引擎把刚刚写入的 redo log 改成**「commit」**（提交）状态，更新完成。</p></li></ol><p><img src="`+k+'" alt="图片"></p><h2 id="q-innodb-事务为什么要两阶段提交" tabindex="-1">Q：Innodb 事务为什么要两阶段提交? <a class="header-anchor" href="#q-innodb-事务为什么要两阶段提交" aria-label="Permalink to &quot;Q：Innodb 事务为什么要两阶段提交?&quot;">​</a></h2><p>本质是为了保证这两个日志逻辑上的一致。</p><p>考虑两种情况：</p><ul><li><p>有 redolog 无 binlog。</p><p>假设在 redolog 写完，binlog 还未写完，这时 MySQL 进程异常重启，导致binlog 里面就没有记录这个语句。然后你会发现，如果需要用这个 binlog 来恢复临时库的话，由于这个语句的 <strong>「binlog 丢失」</strong>，这个临时库就会少了这一次更新，恢复出来的这一行 c 的值就是 0，与原库的值不同。</p></li><li><p>有 binlog 无 redolog。</p><p>如果在 binlog 写完之后 crash，由于 redolog 还没写，崩溃恢复以后这个事务无效，所以这一行c的值是0。但是 binlog 里面已经记录了“把c从0改成1”这个日志。所以，在之后用 binlog 来恢复的时候就**「多了一个事务出来」**，恢复出来的这一行 c 的值就是 1，与原库的值不同。</p></li></ul><p>可以看到，<strong>如果不使用“两阶段提交”，那么数据库的状态就有可能和用它的日志恢复出来的库的状态不一致</strong>。</p><h2 id="q-一条更新语句的执行流程" tabindex="-1">Q：一条更新语句的执行流程？ <a class="header-anchor" href="#q-一条更新语句的执行流程" aria-label="Permalink to &quot;Q：一条更新语句的执行流程？&quot;">​</a></h2><ol><li>执行器先找引擎获取ID=2这一行。ID是主键，存储引擎检索数据，找到这一行。如果ID=2这一行所在的数据页本来就在内存中，就直接返回给执行器；否则，需要先从磁盘读入内存，然后再返回。</li><li>执行器拿到引擎给的行数据，把这个值加上1，比如原来是N，现在就是N+1，得到新的一行数据，再调用引擎接口写入这行新数据。</li><li>引擎将这行新数据更新到内存中，同时将这个更新操作记录到redo log里面，此时redo log处于prepare状态。然后告知执行器执行完成了，随时可以提交事务。</li><li>执行器生成这个操作的binlog，并把binlog写入磁盘。</li><li>执行器调用引擎的提交事务接口，引擎把刚刚写入的redo log改成提交（commit）状态，更新完成。</li></ol><h1 id="日志" tabindex="-1">日志 <a class="header-anchor" href="#日志" aria-label="Permalink to &quot;日志&quot;">​</a></h1><h2 id="bin-log-归档日志" tabindex="-1">bin log：归档日志 <a class="header-anchor" href="#bin-log-归档日志" aria-label="Permalink to &quot;bin log：归档日志&quot;">​</a></h2><p>用于记录用户执行的数据操作型SQL的信息**（DML）**</p><p>二进制文件，<strong>在server层</strong></p><p>作用：主从复制、数据恢复</p><h2 id="undo-log-回滚日志" tabindex="-1">undo log：回滚日志 <a class="header-anchor" href="#undo-log-回滚日志" aria-label="Permalink to &quot;undo log：回滚日志&quot;">​</a></h2><p><strong>InnoDB 存储引擎</strong>特有，用于保证数据的原子性，<strong>「保存了事务发生之前的数据的一个版本，即记录的是修改之前的数据，可用于回滚」</strong>，同时可以提供多版本并发控制下的读（MVCC）。</p><p>作用：事务回滚、实现多版本控制(MVCC)</p><h2 id="redo-log-重做日志" tabindex="-1">redo log：重做日志 <a class="header-anchor" href="#redo-log-重做日志" aria-label="Permalink to &quot;redo log：重做日志&quot;">​</a></h2><p><strong>InnoDB 存储引擎</strong>特有，用于<strong>记录事务操作的变化</strong>（数据修改后的值），不管事务是否提交都会记录。</p><p>执行DML时，log不是直接落盘，而是先记录到内存的redo log buffer（redo日志缓冲区）中，再<strong>批量写入</strong>磁盘文件。写入时机：</p><ol><li><p>buffer空间不足时</p></li><li><p>事务提交时</p></li><li><p>redo log线程大约每秒刷盘一次</p></li><li><p>正常关闭服务器时</p></li><li><p>触发checkpoint规则</p><blockquote><p>redolog buffer、redolog file都是以块（block）方式保存的，称为重做日志块（redo log block），大小固定512B。</p><p>redolog file也是固定大小的，写入方式是<strong>循环利用</strong>。</p><p><code>write_pos</code> 是当前记录的位置，<code>checkpoint</code>是当前要擦除的位置。当<code>write_pos</code>追上<code>checkpoint</code>时，表示redo log日志已经写满。这时候需要执行<code>checkpoint</code>规则腾出可写空间。</p><p><img src="'+u+'" alt="图片"></p></blockquote></li></ol><p>作用：数据恢复、crash-safe</p><h2 id="relay-log-中继日志" tabindex="-1">relay log：中继日志 <a class="header-anchor" href="#relay-log-中继日志" aria-label="Permalink to &quot;relay log：中继日志&quot;">​</a></h2><p>在主从复制中使用，是一个中介临时的日志文件，用于存储从master节点同步过来的binlog</p><h2 id="slow-query-log-慢查询日志" tabindex="-1">slow query log：慢查询日志 <a class="header-anchor" href="#slow-query-log-慢查询日志" aria-label="Permalink to &quot;slow query log：慢查询日志&quot;">​</a></h2><p>记录执行时间超过 <code>long_query_time</code> 这个变量定义的时长的查询语句</p><h2 id="general-log-一般查询日志" tabindex="-1">general log：一般查询日志 <a class="header-anchor" href="#general-log-一般查询日志" aria-label="Permalink to &quot;general log：一般查询日志&quot;">​</a></h2><p>记录用户执行的数据查询型SQL的信息**（DQL）**</p><h2 id="error-log-错误日志" tabindex="-1">error log：错误日志 <a class="header-anchor" href="#error-log-错误日志" aria-label="Permalink to &quot;error log：错误日志&quot;">​</a></h2><p>记录MySQL的启动、运行、关闭过程</p><h2 id="q-redolog-和-binlog-的区别" tabindex="-1">Q：redolog 和 binlog 的区别？ <a class="header-anchor" href="#q-redolog-和-binlog-的区别" aria-label="Permalink to &quot;Q：redolog 和 binlog 的区别？&quot;">​</a></h2><table tabindex="0"><thead><tr><th>redolog</th><th>binlog</th></tr></thead><tbody><tr><td>innodb独有</td><td>server层，所有存储引擎（InnoDB、MyISAM等）都要用</td></tr><tr><td>记录具体修改数据</td><td>记录操作</td></tr><tr><td>循环利用</td><td>满了生成新的</td></tr><tr><td>crash-safe</td><td>不能</td></tr></tbody></table><h1 id="主从复制" tabindex="-1">主从复制 <a class="header-anchor" href="#主从复制" aria-label="Permalink to &quot;主从复制&quot;">​</a></h1><p>指将 <strong>主数据库（Master）<strong>中的 DDL 和 DML 操作通过</strong>binlog</strong>传输到 <strong>从数据库（Slave）</strong> 上，然后将这些日志重新执行（redo），从而使得从数据库的数据与主数据库保持一致。</p><p>MySQL 支持单向、异步复制，复制过程中有一主一从、一主多从。</p><p>作用：</p><ol><li><p>备份</p></li><li><p>读写分离，负载均衡</p></li></ol><p>流程：</p><p>两端三线程</p><ul><li><p>Master 端：binlog线程 —— 记录下所有改变了数据库数据的语句，放进 Master 的 <strong>binlog</strong> 中；</p></li><li><p>Slave 端： I/O 线程 —— 负责从 Master上拉取 binlog 内容，放进自己的<strong>Relay log</strong>中；</p></li><li><p>Slave 端：SQL 执行线程 —— 读取 Relay log，并顺序执行该日志中的 SQL 事件。</p></li></ul><h2 id="q-主从同步延迟如何处理" tabindex="-1">Q：主从同步延迟如何处理？ <a class="header-anchor" href="#q-主从同步延迟如何处理" aria-label="Permalink to &quot;Q：主从同步延迟如何处理？&quot;">​</a></h2><p>原因：一个服务器开放Ｎ个链接给客户端来连接的，这样有会有大并发的更新操作, 但是从服务器的里面读取 binlog 的线程仅有一个，当某个 SQL 在从服务器上执行的时间稍长 或者由于某个 SQL 要进行锁表就会导致<strong>主服务器的 SQL 大量积压</strong>，未被同步到从服务器里。这就导致了主从不一致， 也就是主从延迟。</p><p>解决办法：</p><ol><li><p>写操作后的读操作指定发给数据库主服务器 例如，注册账号完成后，登录时读取账号的读操作也发给数据库主服务器。这种方式和业务强绑定，对业务的侵入和影响较大，如果哪个新来的程序员不知道这样写代码，就会导致一个bug。</p></li><li><p>读从机失败后再读一次主机</p><p>这就是通常所说的 &quot;二次读取&quot; ，二次读取和业务无绑定，只需要对底层数据库访问的 API 进行封装即可，实现代价较小，不足之处在于如果有很多二次读取，将大大增加主机的读操作压力。例如，黑客暴力破解账号，会导致大量的二次读取操作，主机可能顶不住读操作的压力从而崩溃。</p></li><li><p>关键业务读写操作全部指向主机，非关键业务采用<strong>读写分离</strong></p><p>例如，对于一个用户管理系统来说，注册 + 登录的业务读写操作全部访问主机，用户的介绍、爰好、等级等业务，可以采用读写分离，因为即使用户改了自己的自我介绍，在查询时却看到了自我介绍还是旧的，业务影响与不能登录相比就小很多，还可以忍受。</p></li></ol><h2 id="canal" tabindex="-1">Canal <a class="header-anchor" href="#canal" aria-label="Permalink to &quot;Canal&quot;">​</a></h2><p>阿里巴巴开源的数据同步工具，主要应用场景是数据库的<strong>增量数据同步</strong>。</p><p>原理：模拟 MySQL slave 的交互协议，把自己伪装成为一个 MySQL slave ，向 MySQL master 发送<strong>dump协议</strong>，MySQL master 收到 dump 请求后，会被这个伪装的slave ( canal )<strong>拉取 binlog</strong>并 解析成流，然后对接到各个后续的消费者中，如ES、数据库等。</p><h1 id="读写分离" tabindex="-1">读写分离 <a class="header-anchor" href="#读写分离" aria-label="Permalink to &quot;读写分离&quot;">​</a></h1><p><img src="'+m+'" alt="图片"></p><p>主服务器：处理写操作，以及实时性要求高的读操作</p><p>从服务器：处理读操作。</p><p>优点：</p><ul><li>主从服务器负责各自的读和写，极大程度缓解了锁的争用；</li><li>从服务器可以使用 MyISAM，提升查询性能以及节约系统开销；</li><li>增加冗余，提高可用性。</li></ul><p><strong>实现方案</strong></p><p>读写分离常用<strong>代理</strong>方式来实现，代理服务器接收应用层传来的读写请求，然后决定转发到哪个服务器。</p><ol><li><p>基于 MySQL proxy 代理（中间件）</p><p>在应用和数据库之间增加 <strong>代理层</strong>，接收应用对数据库的请求，根据不同请求类型（即是读 read 还是写 write）转发到不同的实例，在实现读写分离的同时可以实现负载均衡。</p><p>MySQL 的代理最常见的是 mysql-proxy、cobar、mycat、Atlas 等。</p></li><li><p>基于应用内路由（代码封装）</p><p>在应用程序中实现，针对不同的请求类型去不同的DB实例执行。</p><p>可基于 spring 的 <strong>aop</strong>：用 aop 来拦截 spring 项目的 dao 层方法，动态切换主从数据源。</p></li><li><p>基于 MySQL-Connector-Java 的 JDBC 驱动方式</p><p>Java 程序通过在连接 MySQL 的 JDBC 中配置主库与从库等地址，JDBC 会自动将读请求发送给从库，将写请求发送给主库，此外， MySQL 的 JDBC 驱动还能够实现多个从库的负载均衡。</p></li><li><p>基于 sharding-jdbc 的方式</p><p>sharding-sphere 是强大的读写分离、分表分库中间件，sharding-jdbc 是 sharding-sphere 的核心模块。</p></li><li><p>UDAL：天翼云DB中间件</p></li></ol><h1 id="分表" tabindex="-1">分表 <a class="header-anchor" href="#分表" aria-label="Permalink to &quot;分表&quot;">​</a></h1><p>常用方案：</p><ol><li><p>纵向拆分（分表）：字段太多的表拆成多个表</p></li><li><p>横向拆分（分库，又称水平分表）：同一个表的数据按某种方式路由，分配到不同的库</p><p>路由即决定数据分到哪里，常按某个键或几个键hash取模，或按某个范围（0-999，1000-1999……）</p></li><li><p>中间表：需要经常join的一些表，拆分重组放入中间表，代替join</p></li><li><p>增加冗余字段</p></li></ol><p>中间件：sharding-jdbc、Mycat、UDAL</p><p>优点：容量大</p><p>缺点：</p><ol><li><p>分布式事务、</p></li><li><p>未带shard查询（导致遍历所有分库）、</p></li><li><p>跨库无法join</p><p>以上解决都需要带shard</p></li><li><p>单实例自增主键无法保证全局唯一</p><p>使用分段预分配id、或使用分布式ID（snowflake算法）</p></li></ol><h1 id="q-mysql使用cpu100-原因" tabindex="-1">Q：MySQL使用CPU100%原因？ <a class="header-anchor" href="#q-mysql使用cpu100-原因" aria-label="Permalink to &quot;Q：MySQL使用CPU100%原因？&quot;">​</a></h1><ol><li>慢sql：优化</li><li>死锁：直接kill查询进程</li><li>访问激增：减少连接数</li></ol><h1 id="查看执行计划-explain" tabindex="-1">查看执行计划（explain） <a class="header-anchor" href="#查看执行计划-explain" aria-label="Permalink to &quot;查看执行计划（explain）&quot;">​</a></h1><p>explain模拟优化器执行SQL语句，除了select，其他比如insert，update和delete均可以使用explain查看执行计划，从而知道mysql是如何处理sql语句，分析查询语句或者表结构的性能瓶颈。</p><p><strong>作用</strong></p><p>1、表的读取顺序 2、数据读取操作的操作类型 3、哪些索引可以使用 4、哪些索引被实际使用 5、表之间的引用 6、每张表有多少行被优化器查询</p><p><strong>用法</strong></p><blockquote><p>explain + SQL语句</p></blockquote><p>执行计划包含的信息，比较重要的字段有：</p><ul><li>select_type : 查询类型，有简单查询、联合查询、子查询等</li><li>type：联结类型，最坏情况为all（扫全表）</li><li>key : 使用的索引</li><li>rows : 扫描的行数</li></ul><table tabindex="0"><thead><tr><th>信息</th><th>描述</th></tr></thead><tbody><tr><td>id</td><td>查询的序号，包含一组数字，表示查询中执行select子句或操作表的顺序<br><strong>两种情况</strong><br>id相同，执行顺序从上往下<br>id不同，id值越大，优先级越高，越先执行</td></tr><tr><td><strong>select_type</strong></td><td>查询类型，主要用于区别普通查询，联合查询，子查询等的复杂查询<br>1、simple ：简单的select查询，不包含子查询或者UNION<br>2、primary ：查询中若包含任何复杂的子部分，最外层查询被标记为primary <br>3、subquery：在select或where中包含了子查询<br>4、derived：衍生，from子句中包含的子查询，MySQL会递归执行这些子查询，把结果放到临时表中<br>5、union：如果第二个select出现在UNION之后，则被标记为UNION，如果union包含在from子句的子查询中，外层select被标记为derived<br>6、union result：UNION 的结果<br></td></tr><tr><td>table</td><td>这行数据在哪个表</td></tr><tr><td>partitions</td><td>匹配的分区（mysql建表时可以水平分区存储，按某个字段进行划分，有key、hash和range等方式）</td></tr><tr><td>type</td><td>显示联结类型，显示查询使用了何种类型，按照从最佳到最坏类型排序<br>1、system：表中仅有一行（=系统表）这是const联结类型的一个特例。<br>2、const：表示通过索引一次就找到，const用于比较primary key或者unique索引。因为只匹配一行数据，所以如果将主键置于where列表中，mysql能将该查询转换为一个常量<br>3、eq_ref:唯一性索引扫描，对于每个索引键，表中只有一条记录与之匹配。常见于唯一索引或者主键扫描<br>4、ref:非唯一性索引扫描，返回匹配某个单独值的所有行，本质上也是一种索引访问，它返回所有匹配某个单独值的行，可能会找多个符合条件的行，属于查找和扫描的混合体<br>5、range:只检索给定范围的行，使用一个索引来选择行。key列显示使用了哪个索引，一般就是where语句中出现了between,in等范围的查询。这种范围扫描索引扫描比全表扫描要好，因为它开始于索引的某一个点，而结束另一个点，不用全表扫描<br>6、index:index 与all区别为index类型只遍历索引树。通常比all快，因为索引文件比数据文件小很多。<br>7、<strong>all：遍历全表</strong>以找到匹配的行<br><strong>注意:一般保证查询至少达到range级别，最好能达到ref。</strong><br></td></tr><tr><td>possible_keys</td><td>指出可能使用哪个索引</td></tr><tr><td><strong>key</strong></td><td>显示<strong>实际决定使用</strong>的键(索引)。如果没有选择索引，键是NULL。查询中如果使用覆盖索引，则该索引和查询的select字段重叠。<br><strong>注意：表数据量太少也可能不走索引</strong></td></tr><tr><td>key_len</td><td>表示索引中使用的字节数，该列计算查询中使用的索引的长度在不损失精度的情况下，长度越短越好。如果键是NULL,则长度为NULL。该字段显示为索引字段的最大可能长度，并非实际使用长度。</td></tr><tr><td>ref</td><td>显示索引的哪一列被使用了，如果有可能是一个常数，哪些列或常量被用于查询索引列上的值</td></tr><tr><td><strong>rows</strong></td><td>根据表统计信息以及索引选用情况，大致估算出找到所需的记录所需要读取的行数。<strong>越小说明查询越快</strong></td></tr><tr><td>filtered</td><td>查询的表行占表的百分比</td></tr><tr><td>Extra</td><td>包含不适合在其他列中显示，但是十分重要的额外信息<br>1、Using filesort：说明mysql会对数据适用一个外部的索引排序。而不是按照表内的索引顺序进行读取。MySQL中无法利用索引完成排序操作称为“文件排序”<br>2、Using temporary:使用了临时表保存中间结果，mysql在查询结果排序时使用临时表。常见于排序order by和分组查询group by。<br>3、Using index:表示相应的select操作用使用覆盖索引，避免访问了表的数据行。如果同时出现using where，表名索引被用来执行索引键值的查找；如果没有同时出现using where，表名索引用来读取数据而非执行查询动作。<br>4、Using where :表明使用where过滤<br>5、using join buffer:使用了连接缓存<br>6、impossible where:where子句的值总是false，不能用来获取任何元组<br>7、select tables optimized away：在没有group by子句的情况下，基于索引优化Min、max操作或者对于MyISAM存储引擎优化count（*），不必等到执行阶段再进行计算，查询执行计划生成的阶段即完成优化。<br>8、distinct：优化distinct操作，在找到第一匹配的元组后即停止找同样值的动作。<br></td></tr><tr><td>dbnode</td><td>（UDAL特有）显示在哪个分片</td></tr></tbody></table>',279)])])}const T=e(f,[["render",x]]);export{A as __pageData,T as default};
